  const ville = (idx >= 0 ? locale.slice(0, idx) : locale).trim() || '';
  const priceMatch = block.match(/Loyer\s*:\s*([\d\s,]+)/);
  const loyerStr = priceMatch ? priceMatch[1].replace(/[^\d,]/g, '').replace(',', '.') : '';
